const query = $input.first().json.query?.q || $input.first().json.query?.query || '';
const count = parseInt($input.first().json.query?.count || '10');
const threshold = parseFloat($input.first().json.query?.threshold || '0.5');
const project = $input.first().json.query?.project || null;

if (!query || query.trim().length === 0) {
  return [{ json: { error: 'Missing query parameter. Use ?q=your+search+query', results: [] } }];
}

return [{ json: { query: query.trim(), count, threshold, project } }];

const embeddingResponse = $input.first().json;
const embedding = embeddingResponse.data[0].embedding;
const params = $('Parse Query Params').first().json;

const body = {
  query_embedding: JSON.stringify(embedding),
  match_threshold: params.threshold,
  match_count: params.count,
  filter_importance: 1
};

if (params.project) {
  body.filter_project = params.project;
}

return [{ json: { rpcBody: JSON.stringify(body) } }];

const results = $input.all().map(item => {
  const m = item.json;
  return {
    summary: m.summary || '',
    details: m.details || '',
    source: m.source || '',
    project: m.project || '',
    type: m.type || '',
    importance: m.importance || 0,
    tags: m.tags || [],
    similarity: m.similarity ? Math.round(m.similarity * 100) / 100 : 0,
    created_at: m.created_at ? m.created_at.substring(0, 10) : ''
  };
});

return [{ json: { count: results.length, results } }];

